400→      const [editId, setEditId]  = useState(null);
401→      const [editForm, setEditForm] = useState({});
402→
403→      const totalExpBudget = events.filter(e => (e.type || "expense") === "expense").reduce((s, e) => s + e.budget, 0);
404→      const totalIncBudget = collectionBudget + events.filter(e => (e.type || "expense") === "income").reduce((s, e) => s + e.budget, 0);
405→      const totalSpent     = events.filter(e => (e.type || "expense") === "expense").reduce((s, e) => s + e.spent, 0);
406→      const cats           = ["הכל", ...CAT_LIST];
407→      const filtered       = filter === "הכל" ? events : events.filter(e => e.category === filter);
408→
409→      const addEvent = () => {
410→        if (!addForm.name.trim()) return;
411→        setEvents([...events, { id: Date.now(), ...addForm, budget: Number(addForm.budget) || 0, spent: Number(addForm.spent) || 0 }]);
412→        setAddForm(EMPTY_EVENT); setShowAdd(false);
413→      };
414→
415→      const startEdit  = (ev) => { setEditId(ev.id); setEditForm({ ...ev, budget: String(ev.budget), spent: String(ev.spent), type: ev.type || "expense" }); };
416→      const cancelEdit = () => setEditId(null);
417→      const saveEdit   = () => {
418→        setEvents(events.map(e => e.id === editId ? { ...editForm, id: editId, budget: Number(editForm.budget) || 0, spent: Number(editForm.spent) || 0 } : e));
419→        setEditId(null);
420→      };
421→      const removeEvent = (id) => { if (window.confirm("למחוק ארוע זה?")) setEvents(events.filter(e => e.id !== id)); };
422→      const toggleDone  = (id) => setEvents(events.map(e => e.id === id ? { ...e, done: !e.done } : e));
423→
424→      const EventForm = ({ data, onChange, onSave, onCancel, title }) => (
425→        <Card style={{ border: "2px solid #ede9fe" }}>
426→          <div style={{ fontWeight: 700, marginBottom: 10, fontSize: 14 }}>{title}</div>
427→          <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
428→            {["expense", "income"].map(t => (
429→              <button key={t} onClick={() => onChange({ ...data, type: t })} style={{
430→                flex: 1, padding: "10px 0", borderRadius: 10, border: "none",
431→                cursor: "pointer", fontFamily: "inherit", fontWeight: 700, fontSize: 13,
432→                background: data.type === t ? (t === "expense" ? "#fee2e2" : "#dcfce7") : "#f1f5f9",
433→                color:      data.type === t ? (t === "expense" ? "#ef4444" : "#059669") : "#94a3b8",
434→              }}>{t === "expense" ? "📤 הוצאה" : "📥 הכנסה"}</button>
435→            ))}
436→          </div>
437→          <FieldLabel>שם הארוע *</FieldLabel>
438→          <input value={data.name} onChange={e => onChange({ ...data, name: e.target.value })} placeholder="שם הארוע" style={S.input} autoFocus />
439→          <FieldLabel>תאריך</FieldLabel>
440→          <input value={data.date} onChange={e => onChange({ ...data, date: e.target.value })} placeholder="תאריך" style={S.input} />
441→          <div style={{ display: "flex", gap: 8 }}>
442→            <div style={{ flex: 1 }}>
443→              <FieldLabel>תקציב ₪</FieldLabel>
444→              <input type="number" value={data.budget} onChange={e => onChange({ ...data, budget: e.target.value })} placeholder="0" style={S.input} />
445→            </div>
446→            <div style={{ flex: 1 }}>
447→              <FieldLabel>{(data.type || "expense") === "income" ? "התקבל ₪" : "שולם ₪"}</FieldLabel>
448→              <input type="number" value={data.spent} onChange={e => onChange({ ...data, spent: e.target.value })} placeholder="0" style={S.input} />
449→            </div>
450→          </div>
451→          <FieldLabel>קטגוריה</FieldLabel>
452→          <select value={data.category} onChange={e => onChange({ ...data, category: e.target.value })} style={S.input}>
453→            {CAT_LIST.map(c => <option key={c}>{c}</option>)}
454→          </select>
455→          <FieldLabel>הערות</FieldLabel>
456→          <input value={data.notes} onChange={e => onChange({ ...data, notes: e.target.value })} placeholder="הערות" style={S.input} />
457→          <FieldLabel>{(data.type || "expense") === "income" ? "נגבה ע״י" : "שולם ע״י"}</FieldLabel>
458→          <input value={data.paidBy || ""} onChange={e => onChange({ ...data, paidBy: e.target.value })} placeholder={(data.type || "expense") === "income" ? "מי גבה" : "שולם ע״י"} style={S.input} />
459→          <label style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, cursor: "pointer", fontSize: 13 }}>
460→            <input type="checkbox" checked={!!data.done} onChange={e => onChange({ ...data, done: e.target.checked })} style={{ width: 16, height: 16 }} />
461→            הושלם ✅
462→          </label>
463→          <div style={{ display: "flex", gap: 8 }}>
464→            <button onClick={onSave} style={S.btn("#7c3aed")} disabled={!data.name.trim()}>שמור</button>
