496→              }}>{c}</button>
497→            ))}
498→          </div>
499→
500→          {/* Event list */}
501→          {filtered.map(ev => {
502→            const isIncome = (ev.type || "expense") === "income";
503→            return editId === ev.id ? (
504→              <EventForm key={ev.id} title="✏️ עריכת ארוע" data={editForm} onChange={setEditForm} onSave={saveEdit} onCancel={cancelEdit} />
505→            ) : (
506→              <Card key={ev.id} style={{ opacity: ev.done ? 0.65 : 1, padding: "12px 14px", borderRight: `3px solid ${isIncome ? "#22c55e" : "#7c3aed"}` }}>
507→                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
508→                  <div style={{ flex: 1, minWidth: 0 }}>
509→                    <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4, flexWrap: "wrap" }}>
