511→                        {ev.done ? "✅" : "⬜"}
512→                      </button>
513→                      <span style={{ fontWeight: 700, fontSize: 14, color: "#0f172a" }}>{ev.name}</span>
514→                      <span style={{ fontSize: 10, fontWeight: 700, padding: "1px 6px", borderRadius: 8, background: isIncome ? "#dcfce7" : "#fee2e2", color: isIncome ? "#059669" : "#ef4444" }}>
515→                        {isIncome ? "📥 הכנסה" : "📤 הוצאה"}
516→                      </span>
517→                    </div>
518→                    <div style={{ display: "flex", gap: 6, alignItems: "center", marginBottom: 4, flexWrap: "wrap" }}>
