const handlePhotoUpload = (e, data, onChange) => {
  const file = e.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = ev => onChange({ ...data, photo: ev.target.result });
  reader.readAsDataURL(file);
};

