file.content:
// Group by paidBy: cash log entries + student payments + budget expenses
const byPerson = {};
cashLog.forEach(c => {
  if (c.paidBy) {
    if (!byPerson[c.paidBy]) byPerson[c.paidBy] = 0;
    byPerson[c.paidBy] += c.amount;
  }
});
students.forEach(s => {
  if (s.paidBy && (s.amount || 0) > 0) {
    if (!byPerson[s.paidBy]) byPerson[s.paidBy] = 0;
    byPerson[s.paidBy] += (s.amount || 0);
  }
});
budgetExpenses.forEach(e => {
  if (e.paidBy) {
    if (!byPerson[e.paidBy]) byPerson[e.paidBy] = 0;
    byPerson[e.paidBy] += e.amount;
  }
});
const personEntries = Object.entries(byPerson);

const addEntry = () => {
  if (!addForm.desc.trim() || !addForm.amount) return;
  const amt = Number(addForm.amount) * (addForm.type === "expense" ? -1 : 1);
  setCashLog([...cashLog, { id: Date.now(), ...addForm, amount: amt }]);
  setAddForm(EMPTY_CASH); setShowAdd(false);
};

const startEdit  = (e) => { setEditId(e.id); setEditForm({ ...e, amount: String(Math.abs(e.amount)), type: e.amount >= 0 ? "income" : "expense" }); };
const cancelEdit = () => setEditId(null);
const saveEdit   = () => {
  const amt = Number(editForm.amount) * (editForm.type === "expense" ? -1 : 1);
  setCashLog(cashLog.map(c => c.id === editId ? { ...editForm, id: editId, amount: amt } : c));
  setEditId(null);
};
const removeEntry = (id) => { if (window.confirm("למחוק תנועה זו?")) setCashLog(cashLog.filter(c => c.id !== id)); };

// running balance
let running = 0;
const withBal = cashLog.map(c => { running += c.amount; return { ...c, bal: running }; });

return (
  <div>
    {/* סה"כ בקופה */}
    <div style={{
      background: "linear-gradient(135deg,#1e293b,#0f172a)",
      borderRadius: 20, padding: 20, color: "white", marginBottom: 12,
    }}>

{/* Breakdown by person */}
{personEntries.length > 0 && (
  <Card style={{ background: "#f8fafc", marginBottom: 12 }}>
    <div style={{ fontWeight: 700, fontSize: 13, color: "#1e293b", marginBottom: 8 }}>💼 לפי נציג</div>
    {personEntries.map(([name, total]) => (
      <div key={name} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "6px 0", borderBottom: "1px solid #f1f5f9" }}>
        <span style={{ fontSize: 13, fontWeight: 600, color: "#0f172a" }}>{name}</span>
        <span style={{ fontSize: 13, fontWeight: 700, color: total >= 0 ? "#059669" : "#ef4444" }}>
          {total >= 0 ? "+" : ""}₪{Math.abs(total).toLocaleString()}
        </span>
      </div>
    ))}
  </Card>
)}

<h3 style={{ fontWeight: 800, fontSize: 15, color: "#1e293b", marginBottom: 10 }}>יומן תנועות</h3>

{/* Budget-derived expenses — read-only */}
{budgetExpenses.length > 0 && (
  <>
    <div style={{ fontSize: 12, fontWeight: 700, color: "#7c3aed", marginBottom: 6, display: "flex", alignItems: "center", gap: 6 }}>
      📊 הוצאות מתקציב
      <span style={{ fontSize: 10, color: "#94a3b8", fontWeight: 400 }}>עריכה רק מלשונית תקציב</span>
    </div>
    {budgetExpenses.map(entry => (
      <div key={entry.id} style={{
        background: "#faf5ff", borderRadius: 12, padding: "12px 14px", marginBottom: 8,
        boxShadow: "0 1px 6px rgba(0,0,0,0.05)", borderRight: "4px solid #a855f7",
      }}>

