// Breakdown by קופה: positive income only — named collectors + unassigned pool
const byKupa = {};
let kupaTotal = 0;
// Student payments
students.forEach(s => {
  if ((s.amount || 0) > 0) {
    if (s.paidBy) { if (!byKupa[s.paidBy]) byKupa[s.paidBy] = 0; byKupa[s.paidBy] += s.amount; }
    else kupaTotal += s.amount;
  }
});
// Manual cash log — positive entries only
cashLog.forEach(c => {
  if (c.amount > 0) {
    if (c.paidBy) { if (!byKupa[c.paidBy]) byKupa[c.paidBy] = 0; byKupa[c.paidBy] += c.amount; }
    else kupaTotal += c.amount;
  }
});
const kupaEntries = Object.entries(byKupa);

